TRACK_DEBOUNCE: float = 0.35          # схлопывание пачки событий SMTC
COVER_TIMEOUT: float = 5.0            # макс. ожидание загрузки обложки

# История (хранится в памяти сервера, обнуляется при перезапуске)
TRACK_HISTORY_MAX: int = 25           # сколько последних треков помнить
SEARCH_HISTORY_MAX: int = 12          # сколько последних запросов помнить

# Токен Яндекс Музыки. Нужен ТОЛЬКО для кнопки «лайк» (всё остальное —
# показ и управление треком — работает и без него).
#
# Как задать свой токен (см. README, раздел «Токен Яндекс Музыки»):
#   1) переменной окружения YANDEX_MUSIC_TOKEN (рекомендуется), ИЛИ
#   2) вписать прямо в кавычки в строке _DEFAULT_YANDEX_TOKEN ниже.
#
# ВНИМАНИЕ: токен = доступ к вашему аккаунту Яндекса. Никогда не публикуйте
