_ICON_512_B64: str = ""


logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(name)s: %(message)s",
)
log = logging.getLogger("winwave")

# Тише сторонние логгеры: httpx иначе печатает каждый запрос к API Яндекса
logging.getLogger("httpx").setLevel(logging.WARNING)
logging.getLogger("httpcore").setLevel(logging.WARNING)


class _SuppressConnResetFilter(logging.Filter):
    """
    Гасит безобидный спам на Windows: когда телефон обрывает соединение с
    обложкой на полуслове, ProactorEventLoop кидает ConnectionResetError
    (WinError 10054). На работу не влияет — просто шумит в консоли.
    """
    def filter(self, record: logging.LogRecord) -> bool:
        msg = record.getMessage()
        if "ConnectionResetError" in msg or "WinError 10054" in msg:
            return False
        if "_call_connection_lost" in msg:
            return False
        # Безобидно: отменённые WinRT-futures при гонке обложек
        if "InvalidStateError" in msg or "invalid state" in msg:
            return False
        if "Future.set_result" in msg:
            return False
        return True


logging.getLogger("asyncio").addFilter(_SuppressConnResetFilter())
